import './App.css'; 
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from 'react-router-dom';
import axios from 'axios';
import Login from './pages/Login';
import Signup from './pages/Signup';
import RegisterComplaint from './pages/RegisterComplaint';

function App() {
  const [complaints, setComplaints] = useState([]);
  const [token, setToken] = useState(localStorage.getItem('token'));

  const fetchComplaints = async () => {
    try {
      const response = await axios.get('http://127.0.0.1:8000/api/complaints/');
      setComplaints(response.data);
    } catch (err) {
      console.error("Backend se connect nahi ho pa raha", err);
    }
  };

  useEffect(() => {
    if (token) {
      fetchComplaints();
    }
  }, [token]);

  const handleResolve = async (id) => {
    try {
      await axios.put(`http://127.0.0.1:8000/api/complaints/${id}/resolve`);
      alert("Status Updated Successfully!");
      fetchComplaints();
    } catch (err) {
      console.error("Update fail ho gaya", err);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setToken(null);
    window.location.href = "/login";
  };

  return (
    <Router>
      {/* --- NEW MODERN NAVIGATION BAR --- */}
      <nav className="navbar">
        <div className="logo-section">
          <div className="logo-circle">G</div>
          <Link to="/" style={{ color: 'white', textDecoration: 'none', fontWeight: '800', fontSize: '22px' }}>
            Grievance<span style={{ color: '#ffcc00' }}>Portal</span>
          </Link>
        </div>

        <div className="nav-links">
          {!token ? (
            <>
              <Link to="/login">Login</Link>
              <Link to="/signup" className="signup-btn">Signup</Link>
            </>
          ) : (
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
              <span style={{ fontSize: '14px', opacity: 0.8, color: 'white' }}>Welcome, User!</span>
              <button onClick={handleLogout} style={{ 
                background: '#ff4b2b', 
                color: 'white', 
                border: 'none', 
                padding: '8px 18px', 
                borderRadius: '20px',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}>Logout</button>
            </div>
          )}
        </div>
      </nav>

      <Routes>
        <Route path="/login" element={!token ? <Login /> : <Navigate to="/" />} />
        <Route path="/signup" element={!token ? <Signup /> : <Navigate to="/" />} />

        <Route path="/" element={token ? (
          <div style={{ padding: '20px', fontFamily: 'Arial', maxWidth: '800px', margin: '0 auto' }}>
            <h1 style={{ color: '#2c3e50', textAlign: 'center' }}>User Dashboard</h1>
            <hr />

            <RegisterComplaint onRefresh={fetchComplaints} />

            <div style={{ marginTop: '30px' }}>
              <h3>Your Registered Complaints:</h3>
              {complaints.length === 0 ? (
                <p style={{ color: 'gray' }}>No complaints found.</p>
              ) : (
                <ul style={{ listStyleType: 'none', padding: 0 }}>
                  {complaints.map((c) => (
                    // --- APPLYING COMPLAINT CARD CLASS ---
                    <li key={c.id} className="complaint-card">
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
                          <b style={{ fontSize: '18px' }}>{c.title}</b> <br />
                          <small style={{ color: '#555' }}>Category: {c.category}</small>
                        </div>
                        <div>
                          <span style={{ 
                            color: c.status === 'Pending' ? 'orange' : 'green', 
                            fontWeight: 'bold', 
                            marginRight: '15px' 
                          }}> 
                            {c.status} 
                          </span>
                          {c.status === 'Pending' && (
                            <button onClick={() => handleResolve(c.id)} className="resolve-btn">
                              Resolve
                            </button>
                          )}
                        </div>
                      </div>
                      <p style={{ marginTop: '10px', color: '#333' }}>{c.description}</p>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        ) : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
